<?php
/**
 * Production-safe content migration for KohTao.Rocks beaches, bays and dive sites.
 * Idempotent: updates existing pages by slug and creates missing pages.
 */

$root = dirname(__DIR__);
$wp_load = $root . '/wp-load.php';
if (!file_exists($wp_load)) {
    fwrite(STDERR, "Cannot find wp-load.php at $wp_load\n");
    exit(1);
}
if (PHP_SAPI !== 'cli') {
    http_response_code(403);
    exit('CLI only');
}
require_once $wp_load;

$version = '2026-07-08-beaches-dive-sites-stage2';
$pages = unserialize(gzuncompress(base64_decode('')));

function ktr_stage2_find_page($slug) {
    global $wpdb;
    return $wpdb->get_row($wpdb->prepare(
        "SELECT ID, post_name FROM {$wpdb->posts} WHERE post_name = %s AND post_type = 'page' AND post_status NOT IN ('trash', 'auto-draft') LIMIT 1",
        $slug
    ));
}

function ktr_stage2_find_attachment_id($slug) {
    global $wpdb;
    if ($slug === '') {
        return 0;
    }
    return (int) $wpdb->get_var($wpdb->prepare(
        "SELECT ID FROM {$wpdb->posts} WHERE post_name = %s AND post_type = 'attachment' LIMIT 1",
        $slug
    ));
}

function ktr_stage2_update_meta($post_id, $key, $value) {
    global $wpdb;
    $meta_id = $wpdb->get_var($wpdb->prepare(
        "SELECT meta_id FROM {$wpdb->postmeta} WHERE post_id = %d AND meta_key = %s LIMIT 1",
        $post_id,
        $key
    ));
    if ($meta_id) {
        $wpdb->update($wpdb->postmeta, array('meta_value' => (string) $value), array('meta_id' => (int) $meta_id), array('%s'), array('%d'));
    } else {
        $wpdb->insert($wpdb->postmeta, array('post_id' => (int) $post_id, 'meta_key' => $key, 'meta_value' => (string) $value), array('%d', '%s', '%s'));
    }
}

function ktr_stage2_upsert_page($page, $parent_id) {
    global $wpdb;
    $existing = ktr_stage2_find_page($page['slug']);
    $now = current_time('mysql');
    $now_gmt = current_time('mysql', true);
    $data = array(
        'post_author' => 1,
        'post_date' => $now,
        'post_date_gmt' => $now_gmt,
        'post_content' => $page['content'],
        'post_title' => $page['title'],
        'post_excerpt' => '',
        'post_status' => $page['status'] ?: 'publish',
        'comment_status' => 'closed',
        'ping_status' => 'closed',
        'post_password' => '',
        'post_name' => $page['slug'],
        'to_ping' => '',
        'pinged' => '',
        'post_modified' => $now,
        'post_modified_gmt' => $now_gmt,
        'post_content_filtered' => '',
        'post_parent' => (int) $parent_id,
        'menu_order' => 0,
        'post_type' => 'page',
        'post_mime_type' => '',
        'comment_count' => 0,
    );
    if ($existing) {
        $wpdb->update($wpdb->posts, $data, array('ID' => (int) $existing->ID));
        return array((int) $existing->ID, 'updated');
    }
    $wpdb->insert($wpdb->posts, $data);
    $post_id = (int) $wpdb->insert_id;
    $wpdb->update($wpdb->posts, array('guid' => home_url('/?page_id=' . $post_id)), array('ID' => $post_id), array('%s'), array('%d'));
    return array($post_id, 'created');
}

$created = array();
$updated = array();
$missing_images = array();
$errors = array();

foreach ($pages as $page) {
    $parent_id = 0;
    if (!empty($page['parent_slug'])) {
        $parent = ktr_stage2_find_page($page['parent_slug']);
        $parent_id = $parent ? (int) $parent->ID : 0;
    }

    list($result, $action) = ktr_stage2_upsert_page($page, $parent_id);
    if (!$result) {
        $errors[] = $page['slug'] . ': database write failed';
        continue;
    }

    ktr_stage2_update_meta($result, '_siteseo_titles_title', $page['seo_title']);
    ktr_stage2_update_meta($result, '_siteseo_titles_desc', $page['seo_desc']);

    if (!empty($page['thumb_slug'])) {
        $thumb_id = ktr_stage2_find_attachment_id($page['thumb_slug']);
        if ($thumb_id) {
            ktr_stage2_update_meta($result, '_thumbnail_id', $thumb_id);
        } else {
            $missing_images[] = $page['slug'] . ' -> ' . $page['thumb_slug'];
        }
    }

    if ($action === 'created') {
        $created[] = $page['slug'];
    } else {
        $updated[] = $page['slug'];
    }
}

update_option('ktr_stage2_beaches_dive_sites_version', $version, false);
flush_rewrite_rules(false);

echo wp_json_encode(array(
    'version' => $version,
    'created' => $created,
    'updated' => $updated,
    'missing_images' => $missing_images,
    'errors' => $errors,
), JSON_PRETTY_PRINT | JSON_UNESCAPED_SLASHES) . PHP_EOL;

if ($errors) {
    exit(1);
}